```c++
#include <QApplication>
#include <QWidget>
#include <QPainter>
#include <QTimer>

class LineChart : public QWidget
{
public:
    LineChart(QWidget *parent = nullptr) : QWidget(parent)
    {
        setFixedSize(500, 300);
        setWindowTitle("Dynamic Line Chart");

        QTimer *timer = new QTimer(this);
        connect(timer, &QTimer::timeout, this, &LineChart::updateData);
        timer->start(1000);
    }

protected:
    virtual void paintEvent(QPaintEvent *) override
    {
        QPainter painter(this);

        painter.setRenderHint(QPainter::Antialiasing);

        // 画坐标轴
        painter.drawLine(originX, originY, originX, originY - height);
        painter.drawLine(originX, originY, originX + width, originY);

        // 绘制折线
        painter.setPen(QPen(Qt::blue, 2));
        const int count = data.size();
        if (count > 1) {
            QPainterPath path;
            const QPointF &p0 = data[0];
            path.moveTo(mapX(p0.x()), mapY(p0.y()));
            for (int i = 1; i < count; ++i) {
                const QPointF &p = data[i];
                path.lineTo(mapX(p.x()), mapY(p.y()));
            }
            painter.drawPath(path);
        }
    }

private:
    void updateData()
    {
        static qreal x = 0;
        static qreal y = qrand() % 100;
        data.push_back(QPointF(x, y));
        x += 1;
        y = qrand() % 100;
        if (data.size() > maxDataCount) {
            data.pop_front();
        }
        update();
    }

    qreal mapX(qreal x) const
    {
        return originX + (x / xRange) * width;
    }

    qreal mapY(qreal y) const
    {
        return originY - (y / yRange) * height;
    }

private:
    QPointF origin{50, 250};
    qreal originX{origin.x()};
    qreal originY{origin.y()};
    qreal width{400};
    qreal height{200};
    qreal xRange{100};
    qreal yRange{100};
    int maxDataCount{100};
    QVector<QPointF> data;
};

int main(int argc, char **argv)
{
    QApplication app(argc, argv);

    LineChart chart;
    chart.show();

    return app.exec();
}
```

该示例代码使用了QWidget作为窗口，继承了QWidget，使用了定时器来模拟不断变化的数据，使用了QPainter进行绘制。相比于前一个示例，添加了一个数据条数的上限，当数据数量超过上限时，自动删除最旧的数据。这样就可以保持折线图一直是动态的。该代码适合对QPainter有一定了解的用户，可以根据需要进行修改和扩展。

