```c++
#include <QApplication>
#include <QWidget>
#include <QPainter>
#include <QTimer>
#include <QDebug>
#include <QFile>
#include <QTextStream>

class CpuUsageChart : public QWidget
{
public:
    CpuUsageChart(QWidget *parent = nullptr) : QWidget(parent)
    {
        setFixedSize(500, 300);
        setWindowTitle("CPU Usage Chart");

        QTimer *timer = new QTimer(this);
        connect(timer, &QTimer::timeout, this, &CpuUsageChart::updateData);
        timer->start(1000);
    }

protected:
    virtual void paintEvent(QPaintEvent *) override
    {
        QPainter painter(this);

        painter.setRenderHint(QPainter::Antialiasing);

        // 画坐标轴
        painter.drawLine(originX, originY, originX, originY - height);
        painter.drawLine(originX, originY, originX + width, originY);

        // 绘制折线
        painter.setPen(QPen(Qt::blue, 2));
        const int count = data.size();
        if (count > 1) {
            QPainterPath path;
            const QPointF &p0 = data[0];
            path.moveTo(mapX(p0.x()), mapY(p0.y()));
            for (int i = 1; i < count; ++i) {
                const QPointF &p = data[i];
                path.lineTo(mapX(p.x()), mapY(p.y()));
            }
            painter.drawPath(path);
        }
    }

private:
    void updateData()
    {
        QFile file("/proc/stat");
        if (!file.exists() || !file.open(QFile::ReadOnly | QFile::Text)) {
            return;
        }

        QTextStream in(&file);
        QString line = in.readLine();
        if (line.isEmpty()) {
            return;
        }

        static qint64 prevIdleTime = -1;
        static qint64 prevTotalTime = -1;
        qint64 idleTime = 0;
        qint64 totalTime = 0;

        const QStringList tokens = line.split(' ');
        if (tokens.size() >= 5) {
            for (int i = 1; i <= 4; ++i) {
                totalTime += tokens[i].toLongLong();
            }
            idleTime = tokens[4].toLongLong();
        }

        const int cpuUsage = prevIdleTime >= 0 ?
            (totalTime - prevTotalTime - (idleTime - prevIdleTime)) * 100 / (totalTime - prevTotalTime) : 0;
        prevIdleTime = idleTime;
        prevTotalTime = totalTime;

        data.push_back(QPointF(data.count(), cpuUsage));
        if (data.size() >= maxDataCount) {
            data.pop_front();
        }

        update();
    }

    qreal mapX(qreal x) const
    {
        return originX + (x / xRange) * width;
    }

    qreal mapY(qreal y) const
    {
        return originY - (y / yRange) * height;
    }

private:
    QPointF origin{50, 250};
    qreal originX{origin.x()};
    qreal originY{origin.y()};
    qreal width{400};
    qreal height{200};
    qreal xRange{100};
    qreal yRange{100};
    int maxDataCount{100};
    QVector<QPointF> data;
};

int main(int argc, char **argv)
{
    QApplication app(argc, argv);

    CpuUsageChart chart;
    chart.show();

    return app.exec();
}
```

该示例代码读取了Linux系统的/proc/stat文件，该文件记录了CPU的使用情况，通过计算CPU的使用率来进行绘制。同样可以通过定时器来模拟不断变化的CPU使用率，使用了QPainter进行绘制。相比于前面的示例，更加贴近实际应用，但需要注意，该示例代码只能在Linux系统上运行。该代码适合对QPainter有一定了解的用户，可以根据需要进行修改和扩展。
